#include <bits/stdc++.h>
using namespace std;
const int N=15;
long long f[N][10];
void init(){
	for(int i=0;i<=9;i++)
		f[1][i]=1;
	for(int i=2;i<N;i++)
		for(int j=0;j<=9;j++)
			for(int k=0;k<=9;k++)
				if(abs(j-k)>=2)
					f[i][j]+=f[i-1][k];
}
long long fac(int x){
	if(!x)
		return 0;
	int n=0,a[N];
	while(x)
		a[++n]=x%10,x/=10;
	int last=-2;
	long long res=0;
	for(int i=n;i;i--){
		for(int j=(i==n);j<a[i];j++)
			if(abs(last-j)>=2)
				res+=f[i][j];
		if(abs(last-a[i])<2)
			break;
		last=a[i];
		if(i==1)
			res++;
	}
	for(int i=1;i<n;i++)
		for(int j=1;j<=9;j++)
			res+=f[i][j];
	return res;
}
int main(){
	init();
	int l,r;
	scanf("%d%d",&l,&r);
	printf("%lld",fac(r)-fac(l-1));
	return 0;
}
